package com.atb.portfolio.utils

import androidx.compose.ui.composed
import androidx.compose.ui.unit.dp
import androidx.compose.animation.core.animateFloatAsState
import androidx.compose.runtime.*
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.graphicsLayer
import androidx.compose.ui.layout.onGloballyPositioned
import androidx.compose.ui.platform.LocalDensity

fun Modifier.scrollReveal(
    revealOffsetDp: Float = 40f
): Modifier = composed {

    var isVisible by remember { mutableStateOf(false) }
    val density = LocalDensity.current

    val offsetPx = with(density) { revealOffsetDp.dp.toPx() }

    val translationY by animateFloatAsState(
        targetValue = if (isVisible) 0f else offsetPx,
        label = "scrollRevealTranslation"
    )

    val alpha by animateFloatAsState(
        targetValue = if (isVisible) 1f else 0f,
        label = "scrollRevealAlpha"
    )

    this
        .onGloballyPositioned {
            // When it enters composition/layout, trigger animation
            isVisible = true
        }
        .graphicsLayer {
            this.translationY = translationY
            this.alpha = alpha
        }
}
