@OptIn(ExperimentalFoundationApi::class)
@Composable
fun HomePage(onAboutClick: () -> Unit) {
    val profile = listOf(
        Profile("LinkedIn", "https://www.linkedin.com", IC_LinkedIn),
        Profile("GitHub", "https://www.github.com", IC_Github),
        Profile("Email", "https://mail.google.com", IC_Email)
    )

    BoxWithConstraints(modifier = Modifier.fillMaxSize()) {
        val isMobile = maxWidth < 768.dp

        if (isMobile) {
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(20.dp),
                horizontalAlignment = Alignment.CenterHorizontally,
                verticalArrangement = Arrangement.Center
            ) {
                // Profile Image first on Mobile
                Image(
                    painter = painterResource(Res.drawable.profile),
                    contentDescription = "Profile Picture",
                    modifier = Modifier
                        .size(250.dp)
                        .clip(CircleShape),
                    contentScale = ContentScale.Crop
                )

                Spacer(modifier = Modifier.height(30.dp))

                HomeContent(
                    profile = profile,
                    onAboutClick = onAboutClick,
                    isMobile = true
                )
            }
        } else {
            Row(
                modifier = Modifier
                    .fillMaxSize()
                    .padding(20.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                Box(
                    modifier = Modifier.weight(1f),
                    contentAlignment = Alignment.Center
                ) {
                    HomeContent(
                        profile = profile,
                        onAboutClick = onAboutClick,
                        isMobile = false
                    )
                }

                Box(
                    modifier = Modifier.weight(1f),
                    contentAlignment = Alignment.Center
                ) {
                    Image(
                        painter = painterResource(Res.drawable.profile),
                        contentDescription = "Profile Picture",
                        modifier = Modifier
                            .size(450.dp)
                            .clip(CircleShape),
                        contentScale = ContentScale.Crop
                    )
                }
            }
        }
    }
}

@OptIn(ExperimentalFoundationApi::class)
@Composable
private fun HomeContent(
    profile: List<Profile>,
    onAboutClick: () -> Unit,
    isMobile: Boolean
) {
    val alignment = if (isMobile) Alignment.CenterHorizontally else Alignment.Start
    val textAlign = if (isMobile) TextAlign.Center else TextAlign.Start

    Column(
        modifier = Modifier.fillMaxWidth(),
        horizontalAlignment = alignment
    ) {
        Text(
            text = "Hi There,\nI'm Ashutosh Bashyal",
            fontFamily = FontFamily.Serif,
            fontSize = if (isMobile) 32.sp else 50.sp,
            lineHeight = if (isMobile) 40.sp else 60.sp,
            fontWeight = FontWeight.ExtraBold,
            color = Color(0xFF6FFFE9),
            textAlign = textAlign
        )

        Spacer(modifier = Modifier.height(20.dp))

        Text(
            text = "I am into Android Development",
            fontFamily = FontFamily(Font(Res.font.CutiveMono_Regular)),
            fontSize = if (isMobile) 20.sp else 30.sp,
            fontWeight = FontWeight.SemiBold,
            color = Color(0xFF5BC0BE),
            textAlign = textAlign
        )

        Spacer(modifier = Modifier.height(30.dp))

        val buttonShape = RoundedCornerShape(15.dp)
        Button(
            modifier = Modifier
                .shadow(5.dp, shape = buttonShape, ambientColor = Color.White),
            onClick = onAboutClick,
            colors = ButtonDefaults.buttonColors(Color(0xFF6FFFE9)),
            shape = buttonShape
        ) {
            Text(
                modifier = Modifier.padding(horizontal = 10.dp, vertical = 5.dp),
                text = "About Me",
                color = Color(0xFF1C2541),
                fontWeight = FontWeight.SemiBold,
                fontSize = if (isMobile) 18.sp else 20.sp
            )
        }

        Spacer(modifier = Modifier.height(30.dp))

        val uriHandler = LocalUriHandler.current

        Row(
            horizontalArrangement = Arrangement.spacedBy(10.dp)
        ) {
            profile.forEach { p ->
                val interactionSource = remember { MutableInteractionSource() }
                val isHovered by interactionSource.collectIsHoveredAsState()
                val scale by animateFloatAsState(if (isHovered) 1.3f else 1f)
                Icon(
                    modifier = Modifier
                        .graphicsLayer(scaleX = scale, scaleY = scale)
                        .hoverable(interactionSource)
                        .padding(8.dp)
                        .size(if (isMobile) 35.dp else 40.dp)
                        .clip(CircleShape)
                        .onClick {
                            uriHandler.openUri(p.url)
                        },
                    imageVector = p.icon,
                    contentDescription = p.name,
                    tint = Color(0xFF5BC0BE)
                )
            }
        }
    }
}
