package com.atb.portfolio

import androidx.compose.foundation.ExperimentalFoundationApi
import androidx.compose.foundation.focusable
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.pager.VerticalPager
import androidx.compose.foundation.pager.rememberPagerState
import androidx.compose.foundation.rememberScrollState
import androidx.compose.foundation.verticalScroll
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.ExperimentalComposeUiApi
import androidx.compose.ui.Modifier
import androidx.compose.ui.focus.FocusRequester
import androidx.compose.ui.focus.focusRequester
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.platform.LocalDensity
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.tooling.preview.Preview
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import com.atb.portfolio.icon.IC_Android
import com.atb.portfolio.icon.IC_Menu
import com.atb.portfolio.model.Pages
import kotlinx.coroutines.launch
import com.atb.portfolio.ui.AboutPage
import com.atb.portfolio.ui.HomePage
import com.atb.portfolio.utils.androidDevBackground
import androidx.compose.ui.input.key.Key
import androidx.compose.ui.input.key.KeyEventType
import androidx.compose.ui.input.key.onKeyEvent
import androidx.compose.ui.input.key.key
import androidx.compose.ui.input.key.type
import androidx.compose.ui.input.pointer.PointerEventType
import androidx.compose.ui.input.pointer.onPointerEvent

@OptIn(ExperimentalFoundationApi::class, ExperimentalComposeUiApi::class, ExperimentalMaterial3Api::class)
@Preview
@Composable
fun App() {
    val pages = listOf(
        Pages("Home", 0),
        Pages("About", 1)
    )

    val pagerState = rememberPagerState(pageCount = { pages.size })
    val mobileScrollState = rememberScrollState()
    val scope = rememberCoroutineScope()
    val focusRequester = remember { FocusRequester() }
    val drawerState = rememberDrawerState(initialValue = DrawerValue.Closed)

    LaunchedEffect(Unit) {
        focusRequester.requestFocus()
    }

    var isScrollLocked by remember { mutableStateOf(false) }

    BoxWithConstraints {
        val isMobile = maxWidth < 768.dp
        val density = LocalDensity.current
        
        // Capture dimensions to avoid scope issues inside Column/Box
        val layoutHeight = maxHeight
        val layoutHeightPx = with(density) { layoutHeight.toPx() }

        // Logic to track current section for background & navigation highlighting
        val currentSection by remember(isMobile, layoutHeightPx) {
            derivedStateOf {
                if (isMobile) {
                    if (layoutHeightPx > 0) (mobileScrollState.value / layoutHeightPx).toInt().coerceIn(0, pages.size - 1) else 0
                } else {
                    pagerState.currentPage
                }
            }
        }

        val backgroundOffset by remember(isMobile, layoutHeightPx) {
            derivedStateOf {
                if (isMobile) {
                    if (layoutHeightPx > 0) mobileScrollState.value / layoutHeightPx else 0f
                } else {
                    pagerState.currentPage + pagerState.currentPageOffsetFraction
                }
            }
        }

        ModalNavigationDrawer(
            drawerState = drawerState,
            gesturesEnabled = isMobile,
            drawerContent = {
                if (isMobile) {
                    ModalDrawerSheet(
                        modifier = Modifier.width(250.dp),
                        drawerContainerColor = Color(0xFF0b132b)
                    ) {
                        Spacer(modifier = Modifier.height(20.dp))
                        pages.forEach { page ->
                            val selected = currentSection == page.index
                            NavigationDrawerItem(
                                label = {
                                    Text(
                                        text = page.name,
                                        color = if (selected) Color(0xFF6fffe9) else Color(0xFF5bc0be)
                                    )
                                },
                                selected = selected,
                                onClick = {
                                    scope.launch {
                                        if (isMobile) {
                                            mobileScrollState.animateScrollTo((page.index * layoutHeightPx).toInt())
                                        } else {
                                            pagerState.animateScrollToPage(page.index)
                                        }
                                        drawerState.close()
                                    }
                                },
                                colors = NavigationDrawerItemDefaults.colors(
                                    selectedContainerColor = Color(0x226fffe9),
                                    unselectedContainerColor = Color.Transparent
                                )
                            )
                        }
                    }
                }
            }
        ) {
            Box(
                modifier = Modifier
                    .fillMaxSize()
                    .focusRequester(focusRequester)
                    .focusable()
                    .onKeyEvent { event ->
                        if (isMobile || event.type != KeyEventType.KeyDown) return@onKeyEvent false
                        when (event.key) {
                            Key.DirectionDown, Key.PageDown -> {
                                if (pagerState.currentPage < pagerState.pageCount - 1) {
                                    scope.launch { pagerState.animateScrollToPage(pagerState.currentPage + 1) }
                                }
                                true
                            }
                            Key.DirectionUp, Key.PageUp -> {
                                if (pagerState.currentPage > 0) {
                                    scope.launch { pagerState.animateScrollToPage(pagerState.currentPage - 1) }
                                }
                                true
                            }
                            else -> false
                        }
                    }
                    .onPointerEvent(PointerEventType.Scroll) { event ->
                        if (isMobile || isScrollLocked) return@onPointerEvent
                        val deltaY = event.changes.first().scrollDelta.y
                        if (deltaY == 0f) return@onPointerEvent
                        val targetPage = when {
                            deltaY > 0 && pagerState.currentPage < pagerState.pageCount - 1 -> pagerState.currentPage + 1
                            deltaY < 0 && pagerState.currentPage > 0 -> pagerState.currentPage - 1
                            else -> null
                        } ?: return@onPointerEvent

                        isScrollLocked = true
                        scope.launch {
                            pagerState.animateScrollToPage(targetPage)
                            isScrollLocked = false
                        }
                    }
                    .androidDevBackground(
                        section = currentSection,
                        pageOffset = backgroundOffset
                    )
            ) {
                Column(modifier = Modifier.fillMaxSize()) {
                    // ---------- TOP BAR ----------
                    CenterAlignedTopAppBar(
                        title = {
                            Row(verticalAlignment = Alignment.CenterVertically) {
                                Icon(
                                    modifier = Modifier.size(24.dp),
                                    imageVector = IC_Android,
                                    contentDescription = null,
                                    tint = Color(0xFF5bc0be),
                                )
                                Spacer(modifier = Modifier.width(8.dp))
                                Text(
                                    text = "Ashutosh",
                                    color = Color(0xFF6fffe9),
                                    fontWeight = FontWeight.Bold,
                                    fontSize = 20.sp
                                )
                            }
                        },
                        navigationIcon = {
                            if (isMobile) {
                                IconButton(onClick = { scope.launch { drawerState.open() } }) {
                                    Icon(imageVector = IC_Menu, contentDescription = "Menu", tint = Color(0xFF6fffe9))
                                }
                            }
                        },
                        actions = {
                            if (!isMobile) {
                                Row(modifier = Modifier.padding(end = 16.dp)) {
                                    pages.forEach { page ->
                                        val selected = currentSection == page.index
                                        TextButton(onClick = {
                                            scope.launch { pagerState.animateScrollToPage(page.index) }
                                        }) {
                                            Text(
                                                text = page.name,
                                                color = if (selected) Color(0xFF6fffe9) else Color(0xFF5bc0be),
                                                fontSize = 16.sp,
                                                fontWeight = if (selected) FontWeight.Bold else FontWeight.Normal
                                            )
                                        }
                                    }
                                }
                            }
                        },
                        colors = TopAppBarDefaults.centerAlignedTopAppBarColors(
                            containerColor = Color(0xFF0b132b)
                        )
                    )

                    // ---------- CONTENT ----------
                    if (isMobile) {
                        // Regular scrolling without snapping for mobile apps
                        Column(
                            modifier = Modifier
                                .fillMaxSize()
                                .verticalScroll(mobileScrollState)
                        ) {
                            pages.forEach { page ->
                                Box(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .height(layoutHeight)
                                ) {
                                    AppContent(page.index) {
                                        scope.launch {
                                            // Action for "About Me" button or similar inside pages
                                            mobileScrollState.animateScrollTo(layoutHeightPx.toInt())
                                        }
                                    }
                                }
                            }
                        }
                    } else {
                        // Snap behavior for desktop via VerticalPager
                        VerticalPager(
                            state = pagerState,
                            modifier = Modifier.fillMaxSize(),
                            userScrollEnabled = false
                        ) { pageIndex ->
                            AppContent(pageIndex) {
                                scope.launch { pagerState.animateScrollToPage(1) }
                            }
                        }
                    }
                }
            }
        }
    }
}

@Composable
fun AppContent(pageIndex: Int, onAboutClick: () -> Unit) {
    when (pageIndex) {
        0 -> HomePage(onAboutClick = onAboutClick)
        1 -> AboutPage()
    }
}
